from flask import Blueprint, Response, jsonify

from apps.api.extensions import get_session
from apps.api.services.filing_service import FilingService

bp = Blueprint("dashboard", __name__)


@bp.get("/")
def dashboard() -> Response:
    html = """<!doctype html><html lang="en"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Filing Intelligence</title><style>
    :root{--midnight:#0B1324;--slate:#15233C;--paper:#F6F4EE;--ink:#112033;--steel:#5F7086;--line:#D5DEEA;--cobalt:#2D5BFF;--aqua:#67D6FF;--emerald:#0C8A6A;--emerald-soft:rgba(12,138,106,.12);--amber:#D38A1F;--amber-soft:rgba(211,138,31,.14);--rose:#B94A5A;--rose-soft:rgba(185,74,90,.12)}
    *{box-sizing:border-box}body{margin:0;font-family:"Avenir Next","Trebuchet MS",sans-serif;color:var(--ink);background:radial-gradient(circle at top left,rgba(103,214,255,.26),transparent 30%),radial-gradient(circle at top right,rgba(45,91,255,.18),transparent 26%),linear-gradient(180deg,#ecf4ff 0,#f4f0e7 100%)}.shell{width:min(1360px,calc(100% - 28px));margin:0 auto;padding:28px 0 54px}.hero,.panel,.metric{border:1px solid rgba(17,32,51,.08);box-shadow:0 20px 50px rgba(17,32,51,.08)}.hero{padding:28px;border-radius:30px;background:radial-gradient(circle at 18% 20%,rgba(103,214,255,.30),transparent 25%),radial-gradient(circle at 84% 16%,rgba(45,91,255,.24),transparent 20%),linear-gradient(135deg,rgba(11,19,36,.98),rgba(21,35,60,.96));color:#fff}.hero-top{display:flex;justify-content:space-between;gap:18px;flex-wrap:wrap}.eyebrow{display:inline-flex;align-items:center;gap:8px;padding:7px 12px;border-radius:999px;background:rgba(255,255,255,.08);color:#c9e6ff;text-transform:uppercase;letter-spacing:.08em;font-size:.76rem}.eyebrow:before{content:"";width:8px;height:8px;border-radius:999px;background:var(--aqua);box-shadow:0 0 18px rgba(103,214,255,.9)}.title{margin:16px 0 8px;font-family:"Iowan Old Style","Palatino Linotype","Book Antiqua",Georgia,serif;font-size:clamp(2.8rem,6vw,4.8rem);line-height:.94;letter-spacing:-.04em;max-width:10ch}.subtitle{max-width:58rem;color:rgba(229,241,255,.8);line-height:1.6;margin:0}.hero-side{display:grid;gap:10px;min-width:250px}.chip{padding:14px 16px;border-radius:18px;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.1)}.chip .k{font-size:.73rem;text-transform:uppercase;letter-spacing:.08em;color:rgba(212,231,255,.76);margin-bottom:6px}.chip .v{font-family:"Cascadia Code","SFMono-Regular",Consolas,monospace}.summary{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:14px;margin:18px 0}.metric,.panel{background:rgba(246,244,238,.94);border-radius:24px}.metric{padding:18px}.metric .k{font-size:.74rem;text-transform:uppercase;letter-spacing:.08em;color:var(--steel);margin-bottom:8px}.metric .v{font-family:"Iowan Old Style","Palatino Linotype","Book Antiqua",Georgia,serif;font-size:2.5rem;line-height:1}.metric .f{margin-top:8px;color:var(--steel);font-size:.9rem}.workspace{display:grid;grid-template-columns:350px minmax(0,1fr);gap:18px}.stack{display:grid;gap:18px}.panel{padding:20px}.panel.dark{background:linear-gradient(160deg,rgba(15,29,54,.98),rgba(21,35,60,.96));color:#fff;border-color:rgba(255,255,255,.08)}.head{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:14px}.head h2,.head h3{margin:0;font-family:"Iowan Old Style","Palatino Linotype","Book Antiqua",Georgia,serif;letter-spacing:-.02em}.muted,.fine{color:var(--steel);line-height:1.55}.dark .muted{color:rgba(229,241,255,.76)}label{display:grid;gap:7px;color:var(--steel);font-size:.82rem;text-transform:uppercase;letter-spacing:.06em}.inputs{display:grid;gap:12px}input{width:100%;padding:13px 14px;border-radius:16px;border:1px solid var(--line);background:rgba(255,255,255,.86);font:inherit;color:var(--ink)}button{border:0;border-radius:999px;padding:12px 16px;font:inherit;font-weight:700;cursor:pointer}.row{display:flex;gap:10px;flex-wrap:wrap}.primary{background:linear-gradient(135deg,var(--cobalt),#1b7fff);color:#fff;box-shadow:0 14px 30px rgba(45,91,255,.24)}.secondary{background:rgba(255,255,255,.9);color:var(--ink);border:1px solid rgba(17,32,51,.08)}.ghost{background:rgba(255,255,255,.08);color:#fff;border:1px solid rgba(255,255,255,.1)}.banner{display:none;margin-top:14px;padding:12px 14px;border-radius:16px}.banner.show{display:block}.info{background:rgba(45,91,255,.1);color:#1f4fe0}.success{background:var(--emerald-soft);color:var(--emerald)}.warn{background:var(--amber-soft);color:#9A5D00}.error{background:var(--rose-soft);color:var(--rose)}.grid2{display:grid;grid-template-columns:minmax(0,1.2fr) minmax(280px,.8fr);gap:16px}.box{padding:16px;border-radius:18px;background:rgba(255,255,255,.72);border:1px solid rgba(17,32,51,.06)}.box .k{font-size:.72rem;text-transform:uppercase;letter-spacing:.08em;color:var(--steel);margin-bottom:8px}.box .t{font-family:"Iowan Old Style","Palatino Linotype","Book Antiqua",Georgia,serif;font-size:1.34rem;margin:0 0 6px}.mini{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.mini .item{padding:14px;border-radius:16px;background:rgba(11,19,36,.04)}.mono{font-family:"Cascadia Code","SFMono-Regular",Consolas,monospace}.table-wrap{overflow-x:auto}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:12px 8px;border-bottom:1px solid rgba(17,32,51,.08);vertical-align:top}th{font-size:.73rem;text-transform:uppercase;letter-spacing:.08em;color:var(--steel)}.pill{display:inline-flex;align-items:center;gap:8px;padding:6px 10px;border-radius:999px;font-size:.76rem;font-weight:700;text-transform:uppercase}.pill:before{content:"";width:8px;height:8px;border-radius:999px;background:currentColor}.p-ok{background:var(--emerald-soft);color:var(--emerald)}.p-run{background:var(--amber-soft);color:#9A5D00}.p-bad{background:var(--rose-soft);color:var(--rose)}.xgrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:14px}.xcard{padding:16px;border-radius:18px;background:rgba(255,255,255,.78);border:1px solid rgba(17,32,51,.06)}.xcard .tag{color:var(--cobalt);font-size:.82rem;margin-bottom:10px}.xcard .val{font-family:"Iowan Old Style","Palatino Linotype","Book Antiqua",Georgia,serif;font-size:1.28rem;margin:10px 0 6px}.empty{padding:18px;border-radius:18px;background:rgba(255,255,255,.7);border:1px dashed rgba(17,32,51,.14);color:var(--steel)}a.link{color:var(--cobalt);text-decoration:none}@media (max-width:1100px){.summary{grid-template-columns:repeat(2,minmax(0,1fr))}.workspace,.grid2{grid-template-columns:1fr}}@media (max-width:720px){.summary,.mini{grid-template-columns:1fr}.shell{width:min(100% - 20px,1360px)}}
    </style></head><body><div class="shell"><section class="hero"><div class="hero-top"><div><div class="eyebrow">Research Control Room</div><h1 class="title">Filing Intelligence</h1><p class="subtitle">Browse SEC company submissions, inspect XBRL facts, queue a 10-company pilot backfill, and watch filings move through extraction and Gemini-powered analysis.</p></div><div class="hero-side"><div class="chip"><div class="k">Pilot Scope</div><div class="v" id="pilot-scope">10 companies | last 2 quarters</div></div><div class="chip"><div class="k">Active Model</div><div class="v" id="ai-provider">gemini</div></div><div class="row"><button class="ghost" id="refresh-button" type="button">Refresh Board</button></div></div></div></section>
    <section class="summary"><article class="metric"><div class="k">Active Companies</div><div class="v" id="company-count">-</div><div class="f">Universe loaded in PostgreSQL</div></article><article class="metric"><div class="k">Filings Stored</div><div class="v" id="filing-count">-</div><div class="f">Deduplicated filings</div></article><article class="metric"><div class="k">Analyzed Filings</div><div class="v" id="analyzed-count">-</div><div class="f">Completed AI runs</div></article><article class="metric"><div class="k">In Flight</div><div class="v" id="active-processing-count">-</div><div class="f">Extraction or analysis pending</div></article></section>
    <section class="workspace"><aside class="stack"><article class="panel dark"><div class="head"><div><h2>Pilot Queue</h2><div class="muted">Prefilled for 10 companies over the last two quarters.</div></div></div><div class="inputs"><label>Start Date<input id="start-date" type="date"/></label><label>End Date<input id="end-date" type="date"/></label><label>Company Limit<input id="limit" type="number" min="1" max="500" value="10"/></label><div class="row"><button class="primary" id="queue-backfill" type="button">Queue Pilot Backfill</button><button class="secondary" id="analyze-pending" type="button">Analyze Pending</button></div><p class="fine">Start with 10 companies and the date window shown here. Once the ingestion flow is stable, we can widen the batch and turn on Polygon later.</p></div><div class="banner" id="status-box"></div></article>
    <article class="panel"><div class="head"><div><h2>SEC Browser</h2><div class="muted">Browse the free SEC.gov endpoints visually from one ticker workspace.</div></div></div><div class="inputs"><label>Ticker<input id="ticker-input" list="ticker-options" value="AAPL" placeholder="AAPL"/><datalist id="ticker-options"></datalist></label><div class="row"><button class="primary" id="load-ticker" type="button">Load SEC View</button><button class="secondary" id="refresh-sec" type="button">Refresh SEC Cache</button></div></div></article></aside>
    <div class="stack"><article class="panel"><div class="head"><div><h2>Company Snapshot</h2><div class="muted">Issuer profile from SEC submissions metadata.</div></div><div class="pill p-run" id="company-state">idle</div></div><div class="grid2"><div id="company-summary"><div class="empty">Load a ticker to see SEC metadata, exchange symbols, and recent submission context.</div></div><div class="box"><div class="k">Notes</div><div class="fine">The SEC browser uses `data.sec.gov` with a declared User-Agent and rate-limited requests. Results are cached for about six hours unless you force-refresh.</div></div></div></article>
    <article class="panel"><div class="head"><div><h2>Recent SEC Filings</h2><div class="muted">Normalized filing rows with direct document URLs.</div></div></div><div class="table-wrap"><table><thead><tr><th>Form</th><th>Filed</th><th>Accession</th><th>Document</th></tr></thead><tbody id="sec-filings-table"><tr><td colspan="4"><div class="empty">No SEC filing data loaded yet.</div></td></tr></tbody></table></div></article>
    <article class="panel"><div class="head"><div><h2>XBRL Concepts</h2><div class="muted">A compact view of recent `us-gaap` facts for the selected issuer.</div></div></div><div class="xgrid" id="xbrl-grid"><div class="empty">Load a ticker to browse normalized XBRL concepts and recent fact values.</div></div></article>
    <article class="panel"><div class="head"><div><h2>Recent Pipeline Filings</h2><div class="muted">Local ingestion state for filings already stored in PostgreSQL.</div></div></div><div class="table-wrap"><table><thead><tr><th>Ticker</th><th>Company</th><th>Filed</th><th>Status</th><th>Action</th></tr></thead><tbody id="filings-table"></tbody></table></div></article></div></section></div>
    <script>
    const banner=document.getElementById("status-box"),tickerInput=document.getElementById("ticker-input"),tickerOptions=document.getElementById("ticker-options");let initialized=false;
    const fmtNum=v=>new Intl.NumberFormat().format(v??0),fmtDate=v=>{if(!v)return"-";const d=new Date(v);return Number.isNaN(d.getTime())?v:d.toLocaleString();},fmtMoney=v=>{if(v===null||v===undefined||v==="")return"-";const n=Number(v);return Number.isNaN(n)?String(v):new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0}).format(n)};
    function setBanner(message,kind="info"){banner.className=`banner show ${kind}`;banner.textContent=message}
    function pill(status){const s=String(status||"unknown").toLowerCase(),span=document.createElement("span");span.className=`pill ${s.includes("fail")?"p-bad":s.includes("analy")||s.includes("extract")||s.includes("pending")?"p-run":"p-ok"}`;span.textContent=s.replaceAll("_"," ");return span}
    function tickers(companies){tickerOptions.innerHTML="";companies.forEach(company=>{const option=document.createElement("option");option.value=company.ticker;option.label=company.name?`${company.ticker} — ${company.name}`:company.ticker;tickerOptions.appendChild(option)})}
    function renderRecent(rows){const table=document.getElementById("filings-table");table.innerHTML="";if(!rows.length){table.innerHTML='<tr><td colspan="5"><div class="empty">No local filings have been stored yet.</div></td></tr>';return}rows.forEach(filing=>{const tr=document.createElement("tr"),cells=[filing.ticker??"-",filing.company_name??"-",fmtDate(filing.filed_at)];cells.forEach(value=>{const td=document.createElement("td");td.textContent=value;tr.appendChild(td)});const status=document.createElement("td");status.appendChild(pill(filing.processing_status));tr.appendChild(status);const action=document.createElement("td"),button=document.createElement("button");button.className="secondary";button.type="button";button.textContent="Analyze";button.onclick=async()=>{const response=await fetch(`/filings/${filing.id}/analyze`,{method:"POST"}),result=await response.json();if(response.ok){const message=result.status==="queued"?`Queued analysis for filing ${result.filing_id}. Task: ${result.task_id}`:`Completed inline analysis for filing ${result.filing_id}.`;setBanner(message,"success");await loadDashboard()}else{setBanner(result.error||"Unable to queue analysis","error")}};action.appendChild(button);tr.appendChild(action);table.appendChild(tr)})}
    function renderCompany(data){document.getElementById("company-state").className="pill p-ok";document.getElementById("company-state").textContent=data.tickers?.[0]||tickerInput.value.toUpperCase();const box=document.getElementById("company-summary"),exchange=(data.exchanges||[]).join(", ")||"Exchange unavailable",tickers=(data.tickers||[]).join(", ")||"Ticker unavailable";box.innerHTML=`<div class="box"><div class="k">Issuer</div><h3 class="t">${data.name||tickerInput.value.toUpperCase()}</h3><div class="muted">${exchange} • ${tickers}</div></div><div class="mini"><div class="item"><div class="k">CIK</div><div class="mono">${data.cik}</div></div><div class="item"><div class="k">SIC</div><div>${data.sic||"-"}</div></div><div class="item"><div class="k">SIC Description</div><div>${data.sic_description||"-"}</div></div><div class="item"><div class="k">Recent Filings</div><div>${(data.filings||[]).length}</div></div></div>`}
    function renderSecFilings(rows){const table=document.getElementById("sec-filings-table");table.innerHTML="";if(!rows.length){table.innerHTML='<tr><td colspan="4"><div class="empty">No recent SEC filings matched this query.</div></td></tr>';return}rows.forEach(filing=>{const tr=document.createElement("tr");[filing.form_type,filing.filing_date].forEach(value=>{const td=document.createElement("td");td.textContent=value;tr.appendChild(td)});const accession=document.createElement("td");accession.className="mono";accession.textContent=filing.accession_number;tr.appendChild(accession);const doc=document.createElement("td"),link=document.createElement("a");link.className="link";link.href=filing.primary_document_url;link.target="_blank";link.rel="noreferrer";link.textContent=filing.primary_document;doc.appendChild(link);tr.appendChild(doc);table.appendChild(tr)})}
    function renderXbrl(concepts){const grid=document.getElementById("xbrl-grid");grid.innerHTML="";if(!concepts.length){grid.innerHTML='<div class="empty">No XBRL concepts were returned for this issuer.</div>';return}concepts.forEach(concept=>{const unit=concept.units?.[0],latest=unit?.values?.[0],meta=latest?`${latest.form??"-"} • ${latest.end??"-"}`:"No recent fact values",card=document.createElement("article");card.className="xcard";card.innerHTML=`<div class="tag mono">${concept.taxonomy}:${concept.tag}</div><h3>${concept.label||concept.tag}</h3><div class="val">${latest?fmtMoney(latest.value):"-"}</div><div class="muted">${meta}</div><div class="muted" style="margin-top:10px">${concept.description||"No description provided."}</div>`;grid.appendChild(card)})}
    async function loadDashboard(){const response=await fetch("/dashboard/data"),data=await response.json();document.getElementById("company-count").textContent=fmtNum(data.company_count);document.getElementById("filing-count").textContent=fmtNum(data.filing_count);document.getElementById("analyzed-count").textContent=fmtNum(data.analyzed_count);document.getElementById("active-processing-count").textContent=fmtNum(data.active_processing_count);document.getElementById("ai-provider").textContent=data.ai_provider;document.getElementById("pilot-scope").textContent=`${data.pilot_defaults.company_limit} companies | ${data.pilot_defaults.start_date} to ${data.pilot_defaults.end_date}`;if(!initialized){document.getElementById("start-date").value=data.pilot_defaults.start_date;document.getElementById("end-date").value=data.pilot_defaults.end_date;document.getElementById("limit").value=data.pilot_defaults.company_limit;if(data.active_companies.length&&!tickerInput.value){tickerInput.value=data.active_companies[0].ticker}initialized=true}tickers(data.active_companies||[]);renderRecent(data.recent_filings||[])}
    async function loadTickerWorkspace(refresh=false){const ticker=tickerInput.value.trim().toUpperCase();if(!ticker){setBanner("Enter a ticker to browse SEC data.","warn");return}document.getElementById("company-state").className="pill p-run";document.getElementById("company-state").textContent="loading";const suffix=refresh?"&refresh=1":"",[company,filings,xbrl]=await Promise.allSettled([fetch(`/api/v1/sec/company/${ticker}?limit=8${suffix}`),fetch(`/api/v1/sec/filings/${ticker}?limit=12&form=10-Q${suffix}`),fetch(`/api/v1/sec/xbrl/${ticker}?taxonomy=us-gaap&concept_limit=12&fact_limit=3${suffix}`)]);if(company.status==="fulfilled"){const payload=await company.value.json();document.getElementById("company-summary").innerHTML=company.value.ok?"":`<div class="empty">${payload.error||"Unable to load SEC company data."}</div>`;if(company.value.ok)renderCompany(payload)}if(filings.status==="fulfilled"){const payload=await filings.value.json();renderSecFilings(filings.value.ok?(payload.filings||[]):[])}if(xbrl.status==="fulfilled"){const payload=await xbrl.value.json();renderXbrl(xbrl.value.ok?(payload.concepts||[]):[])}document.getElementById("company-state").className="pill p-ok";document.getElementById("company-state").textContent=ticker}
    document.getElementById("queue-backfill").onclick=async()=>{const payload={start_date:document.getElementById("start-date").value,end_date:document.getElementById("end-date").value,limit:Number(document.getElementById("limit").value)};const response=await fetch("/filings/backfill",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)}),result=await response.json();if(response.ok){if(result.status==="queued"){setBanner(`Queued backfill task ${result.task_id} for ${payload.limit} companies between ${payload.start_date} and ${payload.end_date}.`,"success")}else{const loaded=(result.results||[]).reduce((sum,row)=>sum+(row.filings_seen||0),0),failed=(result.failures||[]).length;setBanner(`Loaded ${loaded} filings across ${(result.results||[]).length} companies from SEC.gov-backed discovery.${failed?` ${failed} companies failed and can be retried.`:""}`,"success");await loadDashboard()}}else{setBanner(result.error||"Unable to queue backfill.","error")}};
    document.getElementById("analyze-pending").onclick=async()=>{const payload={limit:Number(document.getElementById("limit").value)||25};const response=await fetch("/filings/analyze-pending",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)}),result=await response.json();if(response.ok){const count=(result.completed||result.queued||[]).length;setBanner(`Processed ${count} pending filing${count===1?"":"s"} using ${result.status==="queued"?"the queue":"inline analysis"}.`, "success");await loadDashboard()}else{setBanner(result.error||"Unable to analyze pending filings.","error")}};
    document.getElementById("load-ticker").onclick=()=>loadTickerWorkspace(false);document.getElementById("refresh-sec").onclick=()=>loadTickerWorkspace(true);document.getElementById("refresh-button").onclick=async()=>{await loadDashboard();await loadTickerWorkspace(false);setBanner("Dashboard refreshed.","info")};tickerInput.addEventListener("keydown",event=>{if(event.key==="Enter")loadTickerWorkspace(false)});
    (async()=>{await loadDashboard();await loadTickerWorkspace(false)})();setInterval(loadDashboard,15000);
    </script></body></html>"""
    return Response(html, mimetype="text/html")


@bp.get("/dashboard/data")
def dashboard_data() -> tuple[dict[str, object], int]:
    session = get_session()

    try:
        summary = FilingService(session).get_dashboard_summary()
        return jsonify(summary), 200
    finally:
        session.close()
